Configuration.parameter:
// 20260520 1514 Fixed deleteEntry(), possible putEntry and modEntry too, by changing conn to entry
// 20260530 1531 All modes should be working (in theory) - still testing
// 20260531 1631 Added case sensitivity checkbox for Link Criteria
// 20260602 1430 Connector passed test AL, publishing to github and sharing with the community

// Excel XLSX Connector
// Supports reading and writing Excel .xlsx files using Apache POI
// Unique Key Strategy: Uses specified column or row number as unique identifier

// TODO:
// 1. setting to control if XLS or XLSX is created upon output

// FIX:
// 1. modEntry() changing the wrong row

importPackage(Packages.org.apache.poi.xssf.usermodel);
importPackage(Packages.org.apache.poi.hssf.usermodel);
importPackage(Packages.org.apache.poi.ss.usermodel);
importPackage(Packages.org.apache.poi.ss.util);
importPackage(Packages.java.io);
importPackage(Packages.java.util);
importPackage(Packages.java.text);

// Global variables
var __workbook          = null;
var __sheet             = null;
var __rowIterator       = null;
var __currentRowNum     = 0;
var __columnMap         = null;
var __columnMapFromHeader = false; // true when column map was derived from header row
var __uniqueKeyColumn   = null;
var __dataFormatter     = null;
var __evaluator         = null;
var __rowCache          = null;    // null so lazy-build checks fire correctly
var __rowCacheUIDs       = null;    // null so lazy-build checks fire correctly
var __rowCacheRowNumbers = null;    // null so lazy-build checks fire correctly


// Internal logmsg — accommodates calling from Connector Schema (Connect + Next)
function logmsg(lvl, msg) {
	if (typeof msg == "undefined") {
		msg = lvl;
		lvl = "INFO";
	}
	main.logmsg(lvl, msg);
	java.lang.System.out.println(lvl + " " + msg);
}

// Helper: convert column letter(s) to zero-based index
function getColumnIndex(letter) {
	if (!letter || letter == "") return -1;
	letter = letter.toUpperCase();
	var index = 0;
	for (var i = 0; i < letter.length; i++) {
		index = index * 26 + (letter.charCodeAt(i) - 64);
	}
	return index - 1;
}

// Helper: convert zero-based column index to letter(s)
function getColumnLetter(index) {
	var letter = "";
	while (index >= 0) {
		letter = String.fromCharCode(65 + (index % 26)) + letter;
		index  = Math.floor(index / 26) - 1;
	}
	return letter;
}

// Helper: increment a column letter (e.g. "A" -> "B", "Z" -> "AA")
function incrementColumn(col) {
	var chars = col.split('');
	var i     = chars.length - 1;
	while (i >= 0) {
		if (chars[i] < 'Z') {
			chars[i] = String.fromCharCode(chars[i].charCodeAt(0) + 1);
			return chars.join('');
		}
		chars[i] = 'A';
		i--;
	}
	return 'A' + chars.join('');
}

// Handles all ConnectorInterface exceptions
function handleCIException(methodThrowingException, exception) {
	var msg = "ERROR during " + methodThrowingException + "() operation: " + exception;
	logmsg("ERROR", msg);
	result.setStatus(0);
	result.setMessage(exception);
	throw new java.lang.Exception(msg)
}

// Parse column mappings from configuration string ("A:firstName,B:lastName,...")
function parseColumnMappings(mappingString) {
	var result = new java.util.LinkedHashMap();
	if (!mappingString || mappingString == "") {
		return result;
	}
	var mappings = mappingString.split(",");
	for (var i = 0; i < mappings.length; i++) {
		var parts = mappings[i].trim().split(":");
		if (parts.length == 2) {
			result.put(parts[0].trim().toUpperCase(), parts[1].trim());
		}
	}
	return result;
}

// Get cell value handling all cell types
function getCellValue(cell) {
	if (cell == null) return null;
	try {
		// NOTE: do not call cellType.toString() — that produces a string like "1"
		// which never matches the integer constants (CELL_TYPE_STRING etc.)
		var cellType = cell.getCellType();
		switch (cellType) {
			case cell.CELL_TYPE_STRING:
				return cell.getStringCellValue();
			case cell.CELL_TYPE_NUMERIC:
				if (DateUtil.isCellDateFormatted(cell)) {
					var dateValue     = cell.getDateCellValue();
					var dateFormatStr = connector.getParam("dateFormat");
					if (dateFormatStr && dateFormatStr != "") {
						return new java.text.SimpleDateFormat(dateFormatStr).format(dateValue);
					}
					return dateValue.toString();
				}
				return cell.getNumericCellValue().toString();
			case cell.CELL_TYPE_BOOLEAN:
				return cell.getBooleanCellValue().toString();
			case cell.CELL_TYPE_FORMULA:
				try {
					return __dataFormatter.formatCellValue(cell, __evaluator);
				} catch (e) {
					return cell.getCellFormula();
				}
			case cell.CELL_TYPE_BLANK:
				return null;
			default:
				return __dataFormatter.formatCellValue(cell);
		}
	} catch (e) {
		logmsg("ERROR", "Error getting cell value: " + e);
		return null;
	}
}

// Save workbook back to disk
function saveWorkbook() {
	var filePath = connector.getParam("excelFilePath");
	var fos      = new java.io.FileOutputStream(filePath);
	__workbook.write(fos);
	fos.close();
}

// Return the __rowCache value associated with the passed key
function returnRowCacheEntry(key_UID_or_LineNum) {
	// See if its a configured index column
	var foundOne = __rowCache.get(key_UID_or_LineNum);
	if (!foundOne) {
		// If not, check for $uid or $rowNumber
		var actualKey = __rowCacheUIDs.get(key_UID_or_LineNum) || __rowCacheRowNumbers.get(key_UID_or_LineNum);
		foundOne = __rowCache.get(actualKey)
	}
}

// Build row cache (key -> Row) for fast lookup in findEntry/modEntry/deleteEntry
function buildRowCache() {
	__rowCache = new java.util.HashMap();
	__rowCacheUIDS = new java.util.HashMap();
	__rowCacheRowNumbers = new java.util.HashMap();

	var iter   = __sheet.iterator();

	if (connector.getParam("skipHeader") == "true" || __columnMapFromHeader) {
		if (iter.hasNext()) iter.next();
	}

	var uniqueKeyColIndex = getColumnIndex(__uniqueKeyColumn);

	while (iter.hasNext()) {
		var row      = iter.next();
		var rowNum = row.getRowNum().toString();
		var uidCellValue = null;
		if (uniqueKeyColIndex >= 0) {
			uidCellValue = getCellValue(row.getCell(uniqueKeyColIndex));
		}
		var keyValue = (uniqueKeyColIndex >= 0)
			? uidCellValue
			: rowNum;
		if (keyValue != null) {
			__rowCache.put(keyValue, row);
			__rowCacheRowNumbers.put(rowNum, keyValue);
			__rowCacheUIDS.put(uidCellValue, keyValue)
		}
	}
	logmsg("Built row cache with " + __rowCache.size() + " entries");
}

function initialize() {
	logmsg("Initializing Excel XLSX Connector...");
	try {
		var filePath   = connector.getParam("excelFilePath");
		var sheetName  = connector.getParam("sheetName");
		var sheetIndex = connector.getParam("sheetIndex");

		if (!filePath || filePath == "") {
			throw new java.lang.Exception("Excel file path is required");
		}

		__uniqueKeyColumn = connector.getParam("uniqueKeyColumn") || null;
		if (__uniqueKeyColumn == "") __uniqueKeyColumn = null;

		if (__uniqueKeyColumn) {
			logmsg("Using column " + __uniqueKeyColumn + " as unique key");
		} else {
			logmsg("No unique key column specified, using row number");
		}

		var file = new java.io.File(filePath);
		if (!file.exists()) {
			if (connector.getParam("createIfNotExists") == "true") {
				logmsg("Creating new Excel file: " + filePath);
				__workbook = new org.apache.poi.xssf.usermodel.XSSFWorkbook();
				__sheet    = __workbook.createSheet(sheetName || "Sheet1");
				saveWorkbook();
			} else {
				throw new java.lang.Exception("Excel file not found: " + filePath);
			}
		} else {
			// Detect XLSX vs XLS by magic bytes rather than file extension
			var fis    = new java.io.FileInputStream(file);
			var header = java.lang.reflect.Array.newInstance(java.lang.Byte.TYPE, 4);
			fis.read(header);
			fis.close();

			fis = new java.io.FileInputStream(file);
			// XLSX is a ZIP file — magic bytes PK (0x50 0x4B)
			if ((header[0] & 0xFF) == 0x50 && (header[1] & 0xFF) == 0x4B) {
				__workbook = new org.apache.poi.xssf.usermodel.XSSFWorkbook(fis);
			// XLS is OLE2 — magic bytes 0xD0 0xCF
			} else if ((header[0] & 0xFF) == 0xD0 && (header[1] & 0xFF) == 0xCF) {
				__workbook = new org.apache.poi.hssf.usermodel.HSSFWorkbook(fis);
			} else {
				throw new java.lang.Exception("Unrecognised file format: " + filePath);
			}
			fis.close();

			if (sheetName && sheetName != "") {
				__sheet = __workbook.getSheet(sheetName);
				if (__sheet == null) {
					throw new java.lang.Exception("Sheet not found: " + sheetName);
				}
			} else {
				var idx = parseInt(sheetIndex || "0");
				if (idx < 0 || idx >= __workbook.getNumberOfSheets()) {
					throw new java.lang.Exception("Invalid sheet index: " + idx);
				}
				__sheet = __workbook.getSheetAt(idx);
			}
		}

		__dataFormatter = new org.apache.poi.ss.usermodel.DataFormatter();
		__evaluator     = __workbook.getCreationHelper().createFormulaEvaluator();

		// Resolve column map — connector parameter takes priority, header row is the fallback
		__columnMap = parseColumnMappings(connector.getParam("columnMappings"));

		if (__columnMap.size() > 0) {
			__columnMapFromHeader = false;
			logmsg("Column map from connector parameters: " + __columnMap.size() + " columns");
		} else {
			// No mappings configured — read row 0 directly using sheet.getRow()
			// so no iterator is consumed here
			var headerRow = __sheet.getRow(0);
			if (headerRow == null) {
				throw new java.lang.Exception("No column mappings configured and sheet has no header row");
			}
			var columnLetter = "A";
			var cellIter     = headerRow.cellIterator();
			while (cellIter.hasNext()) {
				var cell  = cellIter.next();
				var value = getCellValue(cell) || "";
				__columnMap.put(columnLetter, system.splitString(value, "\n")[0]);
				columnLetter = incrementColumn(columnLetter);
			}
			__columnMapFromHeader = true;
			logmsg("Column map built from header row: " + __columnMap.size() + " columns");
		}

		logmsg("Connector initialised — sheet: " + __sheet.getSheetName() + ", rows: " + __sheet.getLastRowNum());

	} catch (e) {
		logmsg("ERROR", "Error initialising connector: " + e);
		throw e;
	}
}

function selectEntries(searchFilter) {
	logmsg("selectEntries called");

	__rowIterator   = __sheet.iterator();
	__currentRowNum = 0;

	try {
		// Advance to startRow
		var startRow = parseInt(connector.getParam("startRow") || "0");
		while (__currentRowNum < startRow && __rowIterator.hasNext()) {
			__rowIterator.next();
			__currentRowNum++;
		}
/*	
		// Skip the header row if the column map was derived from it,
		// or if explicit mappings are configured and skipHeader is set.
		// The two cases are mutually exclusive — __columnMapFromHeader
		// is only true when no connector parameter mappings were provided.
		if (__columnMapFromHeader || connector.getParam("skipHeader") == "true") {
			if (__rowIterator.hasNext()) {
				__rowIterator.next();
				__currentRowNum++;
				logmsg("Header row skipped");
			}
		}
*/

		logmsg("selectEntries ready — starting from sheet row " + __currentRowNum);
	} catch(e) {
		handleCIException("selectEntries", e)
	}
}

function getNextEntry() {
	entry.removeAllAttributes();

	var endRow = parseInt(connector.getParam("endRow") || "-1");
	if (endRow >= 0 && __currentRowNum > endRow) {
		result.setStatus(0);
		result.setMessage("End row reached");
		return;
	}

	if (!__rowIterator.hasNext()) {
		result.setStatus(0);
		result.setMessage("End of input");
		return;
	}

	try {
		var row = __rowIterator.next();
		__currentRowNum++;

		entry.merge(buildEntryFromRow(row));
		result.setStatus(1);

	} catch (e) {
		handleCIException("getNextEntry", e)
	}
}

function putEntry() {
	logmsg("putEntry called");
	try {
		var writeMode = connector.getParam("writeMode") || "append";
		if (writeMode != "append") {
			throw new java.lang.Exception("Only 'append' writeMode is supported in putEntry");
		}

		var newRowNum = __sheet.getLastRowNum() + 1;
		var row       = __sheet.createRow(newRowNum);
		var keys      = __columnMap.keySet().toArray();

		for (var i = 0; i < keys.length; i++) {
			var colLetter = keys[i];
			var attrName  = __columnMap.get(colLetter);
			var colIndex  = getColumnIndex(colLetter);
			if (entry.getAttribute(attrName) != null) {
				row.createCell(colIndex).setCellValue(entry.getString(attrName));
			}
		}

		saveWorkbook();
		logmsg("Added new row at position: " + newRowNum);
		result.setStatus(1);

	} catch (e) {
		handleCIException("putEntry", e)
	}
}

function modEntry() {
	logmsg("modEntry called");
	try {
		if (__rowCache == null) buildRowCache();

		var fromLookup = connector.getFirstFindEntry();
		if (fromLookup) {
			for (var att in fromLookup) {
				if (!entry[att.getName()]) {
					entry.setAttribute(att)
				}
			}
			//entry["$uid"] = fromLookup["$uid"]
		}

		var keyValue;
		if (__uniqueKeyColumn != null) {
			keyValue = entry.getString(__columnMap.get(__uniqueKeyColumn));
		} else {
			keyValue = entry.getString("$uid") || entry.getString("$rowNumber");
		}

		if (keyValue == null) {
			throw new java.lang.Exception("Cannot modify entry: unique key value not found in conn");
		}

		var row = __rowCache.get(keyValue);
		if (row == null) {
			throw new java.lang.Exception("Row not found for key: " + keyValue);
		}

		var keys = __columnMap.keySet().toArray();
		for (var i = 0; i < keys.length; i++) {
			var colLetter = keys[i];
			var attrName  = __columnMap.get(colLetter);
			var colIndex  = getColumnIndex(colLetter);
			if (entry.getAttribute(attrName) != null) {
				var cell = row.getCell(colIndex) || row.createCell(colIndex);
				cell.setCellValue(entry.getString(attrName));
			}
		}

		saveWorkbook();
		logmsg("Modified row: " + row.getRowNum());
		result.setStatus(1);

	} catch (e) {
		handleCIException("modEntry", e)
	}
}

function deleteEntry() {
	logmsg("deleteEntry called");
	try {
		if (__rowCache == null) buildRowCache();

		var keyValue;
		if (__uniqueKeyColumn != null) {
			keyValue = entry.getString(__columnMap.get(__uniqueKeyColumn));
		} else {
			keyValue = entry.getString("$uid") || entry.getString("$rowNumber");
		}

		if (keyValue == null) {
			throw new java.lang.Exception("Cannot delete entry: unique key value not found in conn");
		}

		var row = __rowCache.get(keyValue);
		if (row == null) {
			throw new java.lang.Exception("Row not found for key: " + keyValue);
		}

		var rowNum = row.getRowNum();
		__sheet.removeRow(row);
		if (rowNum < __sheet.getLastRowNum()) {
			__sheet.shiftRows(rowNum + 1, __sheet.getLastRowNum(), -1);
		}

		saveWorkbook();
		logmsg("Deleted row: " + rowNum);

		__rowCache = null; // Force rebuild — row numbers have shifted
		result.setStatus(1);

	} catch (e) {
		handleCIException("deleteEntry", e)
	}
}

function findEntry() {
	logmsg("findEntry called");
	try {
		connector.clearFindEntries();

		if (__rowCache == null) buildRowCache();

		var searchResults   = new java.util.ArrayList();
		var searchType      = search.getType();
		var criteriaCount   = search.size();
		var fastPathHandled = false;

		// Fast-path: single EXACT match on unique key, $uid, or $rowNumber
		if (criteriaCount == 1) {
			var crit          = search.getCriteria(0);
			var uniqueKeyAttr = (__uniqueKeyColumn != null) ? __columnMap.get(__uniqueKeyColumn) : null;

			if (crit.match == search.EXACT &&
				(crit.name == uniqueKeyAttr || crit.name == "$uid" || crit.name == "$rowNumber")) {
				fastPathHandled = true;
				var row = __rowCache.get(crit.value);
				if (row != null) {
					searchResults.add(buildEntryFromRow(row));
				}
			}
		}

		// Full scan — only if fast-path key lookup was not applicable
		if (!fastPathHandled) {
			var iter = __sheet.iterator();
			if (__columnMapFromHeader || connector.getParam("skipHeader") == "true") {
				if (iter.hasNext()) iter.next();
			}

			while (iter.hasNext()) {
				var row        = iter.next();
				var candidate  = buildEntryFromRow(row);
				var matchCount = 0;

				for (var i = 0; i < criteriaCount; i++) {
					var crit = search.getCriteria(i);
					if (evaluateCriteria(candidate.getString(crit.name), crit.match, crit.value)) {
						matchCount++;
					}
				}

				var rowMatches;
				if (searchType == search.SEARCH_OR) {
					rowMatches = (matchCount > 0);
				} else if (searchType == search.SEARCH_NOT) {
					rowMatches = (matchCount == 0);
				} else { // SEARCH_AND (default)
					rowMatches = (matchCount == criteriaCount);
				}

				if (rowMatches) {
					searchResults.add(candidate);
				}
			}
		}

		if (searchResults.size() == 0) {
			result.setStatus(0);
			result.setMessage("No entries found");
		} else {
			result.setStatus(1);
			entry.removeAllAttributes();
			entry.merge(searchResults.get(0));
			for (var i = 0; i < searchResults.size(); i++) {
				connector.addFindEntry(searchResults.get(i));
			}
		}

	} catch (e) {
		handleCIException("findEntry", e)
	}
}

// Build an Entry from a POI Row using the current column map.
// Always sets every mapped attribute — blank cells write empty string
// to prevent value carry-over from the previous row via entry.merge().
function buildEntryFromRow(row) {
	var e    = system.newEntry();
	var keys = __columnMap.keySet().toArray();

	e.setAttribute("$rowNumber", row.getRowNum().toString());

	for (var i = 0; i < keys.length; i++) {
		var colLetter = keys[i];
		var attrName  = __columnMap.get(colLetter);
		var colIndex  = getColumnIndex(colLetter);
		var cellValue = getCellValue(row.getCell(colIndex));
		e.setAttribute(attrName, cellValue != null ? cellValue : "");
	}

	var dn = (__uniqueKeyColumn != null)
		? getCellValue(row.getCell(getColumnIndex(__uniqueKeyColumn)))
		: row.getRowNum().toString();
	e.setAttribute("$uid", dn);

	return e;
}

// Convert the value passed to a Float if possible
function numOrText(val, otherVal) {
	if (typeof(otherVal) == "string") {
		return String(val).trim()
	}

	try {
		var newVal = java.lang.Float(val);
		return newVal
	} catch(ex) {
		return val
	}
}

function evaluateCriteria(attrValue, matchType, searchValue) {
	if (attrValue == null) return false;

	var caseSensitive	= connector.getParam("caseSensitiveSearch");
	var a = numOrText(attrValue.toString());
	var s = numOrText((searchValue != null) ? searchValue.toString() : "", a);
	if (caseSensitive) {
		a = a.toUpperCase();
		s = s.toUpperCase()
	}


	if (matchType == search.EXACT)                 return a == s;
	if (matchType == search.NOT_STRING)            return a != s;
	if (matchType == search.SUBSTRING)             return a.indexOf(s) >= 0;
	if (matchType == search.INITIAL_STRING)        return a.indexOf(s) == 0;
	if (matchType == search.FINAL_STRING)          return a.length >= s.length && a.lastIndexOf(s) == a.length - s.length;

	if (matchType == search.LESS_THAN)             return a < s;
	if (matchType == search.LESS_THAN_OR_EQUAL)    return a <= s;
	if (matchType == search.GREATER_THAN)          return a > s;
	if (matchType == search.GREATER_THAN_OR_EQUAL) return a >= s;
/*
	if (matchType == search.LESS_THAN)             return parseFloat(a) < parseFloat(s);
	if (matchType == search.LESS_THAN_OR_EQUAL)    return parseFloat(a) <= parseFloat(s);
	if (matchType == search.GREATER_THAN)          return parseFloat(a) > parseFloat(s);
	if (matchType == search.GREATER_THAN_OR_EQUAL) return parseFloat(a) >= parseFloat(s);
*/
	logmsg("WARN", "evaluateCriteria: unhandled match type " + matchType);
	return false;
}

function querySchema() {
	logmsg("querySchema called");
	try {
		var keys = __columnMap.keySet().toArray();
		for (var i = 0; i < keys.length; i++) {
			var schemaEntry = system.newEntry();
			schemaEntry.addAttributeValue("name", __columnMap.get(keys[i]));
			schemaEntry.addAttributeValue("syntax", "String");
			list.add(schemaEntry);
		}

		var rowNumEntry = system.newEntry();
		rowNumEntry.addAttributeValue("name", "$rowNumber");
		rowNumEntry.addAttributeValue("syntax", "String");
		list.add(rowNumEntry);

		var dnEntry = system.newEntry();
		dnEntry.addAttributeValue("name", "$uid");
		dnEntry.addAttributeValue("syntax", "String");
		list.add(dnEntry);

		result.setStatus(1);

	} catch (e) {
		handleCIException("querySchema", e)
	}
}

function terminate() {
	logmsg("Terminating Excel XLSX Connector...");
	try {
		if (__workbook != null) {
			__workbook.close();
		}
	} catch (e) {
		logmsg("WARN", "Error closing workbook: " + e);
	} finally {
		__workbook            = null;
		__sheet               = null;
		__rowIterator         = null;
		__columnMap           = null;
		__columnMapFromHeader = false;
		__rowCache            = null;
		__evaluator           = null;
		__dataFormatter       = null;
		logmsg("Excel XLSX Connector terminated");
	}
}

// Excel XLSX Connector
// Supports reading and writing Excel .xlsx files using Apache POI
// Unique Key Strategy: Uses specified column or row number as unique identifier

// Import required Java packages
importPackage(Packages.org.apache.poi.xssf.usermodel);
importPackage(Packages.org.apache.poi.ss.usermodel);
importPackage(Packages.org.apache.poi.ss.util);
importPackage(Packages.java.io);
importPackage(Packages.java.util);
importPackage(Packages.java.text);

// Global variables
var workbook = null;
var sheet = null;
var rowIterator = null;
var currentRowNum = 0;
var columnMap = null;
var uniqueKeyColumn = null;
var dataFormatter = null;
var evaluator = null;
var rowCache = null; // Cache for update operations

// Helper function to convert column letter to index
function getColumnIndex(letter) {
    if (!letter || letter == "") return -1;
    letter = letter.toUpperCase();
    var index = 0;
    for (var i = 0; i < letter.length; i++) {
        index = index * 26 + (letter.charCodeAt(i) - 64);
    }
    return index - 1;
}

// Helper function to convert column index to letter
function getColumnLetter(index) {
    var letter = "";
    while (index >= 0) {
        letter = String.fromCharCode(65 + (index % 26)) + letter;
        index = Math.floor(index / 26) - 1;
    }
    return letter;
}

// Parse column mappings from configuration
function parseColumnMappings(mappingString) {
    var map = new java.util.HashMap();
    if (!mappingString || mappingString == "") {
        return map;
    }

    var mappings = mappingString.split(",");
    for (var i = 0; i < mappings.length; i++) {
        var parts = mappings[i].trim().split(":");
        if (parts.length == 2) {
            var colLetter = parts[0].trim().toUpperCase();
            var attrName = parts[1].trim();
            map.put(colLetter, attrName);
        }
    }
    return map;
}

// Get cell value handling different types
function getCellValue(cell) {
    if (cell == null) {
        return null;
    }

    try {
        var cellType = cell.getCellType();

        switch(cellType.toString()) {
            case "STRING":
                return cell.getStringCellValue();
            case "NUMERIC":
                if (DateUtil.isCellDateFormatted(cell)) {
                    var dateValue = cell.getDateCellValue();
                    var dateFormatStr = connector.getParam("dateFormat");
                    if (dateFormatStr && dateFormatStr != "") {
                        var sdf = new SimpleDateFormat(dateFormatStr);
                        return sdf.format(dateValue);
                    }
                    return dateValue.toString();
                }
                return cell.getNumericCellValue().toString();
            case "BOOLEAN":
                return cell.getBooleanCellValue().toString();
            case "FORMULA":
                try {
                    var cellValue = evaluator.evaluate(cell);
                    return dataFormatter.formatCellValue(cell, evaluator);
                } catch (e) {
                    return cell.getCellFormula();
                }
            case "BLANK":
                return null;
            default:
                return dataFormatter.formatCellValue(cell);
        }
    } catch (e) {
        connector.logmsg("Error getting cell value: " + e);
        return null;
    }
}

// Build row cache for update operations
function buildRowCache() {
    rowCache = new java.util.HashMap();
    var iter = sheet.iterator();

    // Skip header if configured
    if (connector.getParam("skipHeader") == "true" && iter.hasNext()) {
        iter.next();
    }

    var uniqueKeyColIndex = getColumnIndex(uniqueKeyColumn);

    while (iter.hasNext()) {
        var row = iter.next();
        var keyValue;

        if (uniqueKeyColIndex >= 0) {
            var keyCell = row.getCell(uniqueKeyColIndex);
            keyValue = getCellValue(keyCell);
        } else {
            // Use row number as key
            keyValue = row.getRowNum().toString();
        }

        if (keyValue != null) {
            rowCache.put(keyValue, row);
        }
    }

    connector.logmsg("Built row cache with " + rowCache.size() + " entries");
}

function initialize() {
    connector.logmsg("Initializing Excel XLSX Connector...");

    try {
        var filePath = connector.getParam("excelFilePath");
        var sheetName = connector.getParam("sheetName");
        var sheetIndex = connector.getParam("sheetIndex");

        if (!filePath || filePath == "") {
            throw new java.lang.Exception("Excel file path is required");
        }

        // Parse column mappings
        var mappingString = connector.getParam("columnMappings");
        columnMap = parseColumnMappings(mappingString);

        // Get unique key column
        uniqueKeyColumn = connector.getParam("uniqueKeyColumn");
        if (!uniqueKeyColumn || uniqueKeyColumn == "") {
            uniqueKeyColumn = null; // Will use row number
            connector.logmsg("No unique key column specified, using row number");
        } else {
            connector.logmsg("Using column " + uniqueKeyColumn + " as unique key");
        }

        // Check if file exists
        var file = new java.io.File(filePath);
        if (!file.exists()) {
            if (connector.getParam("createIfNotExists") == "true") {
                connector.logmsg("Creating new Excel file: " + filePath);
                workbook = new XSSFWorkbook();
                sheet = workbook.createSheet(sheetName || "Sheet1");

                // Save the new file
                var fileOutputStream = new FileOutputStream(filePath);
                workbook.write(fileOutputStream);
                fileOutputStream.close();
            } else {
                throw new java.lang.Exception("Excel file not found: " + filePath);
            }
        } else {
            // Open existing file
            var fileInputStream = new FileInputStream(filePath);
            workbook = new XSSFWorkbook(fileInputStream);
            fileInputStream.close();

            // Get sheet by name or index
            if (sheetName && sheetName != "") {
                sheet = workbook.getSheet(sheetName);
                if (sheet == null) {
                    throw new java.lang.Exception("Sheet not found: " + sheetName);
                }
            } else {
                var idx = parseInt(sheetIndex || "0");
                if (idx < 0 || idx >= workbook.getNumberOfSheets()) {
                    throw new java.lang.Exception("Invalid sheet index: " + idx);
                }
                sheet = workbook.getSheetAt(idx);
            }
        }

        // Initialize data formatter and evaluator
        dataFormatter = new DataFormatter();
        evaluator = workbook.getCreationHelper().createFormulaEvaluator();

        connector.logmsg("Excel XLSX Connector initialized successfully");
        connector.logmsg("Sheet: " + sheet.getSheetName() + ", Rows: " + sheet.getLastRowNum());

    } catch (e) {
        connector.logmsg("Error initializing connector: " + e);
        throw e;
    }
}

function selectEntries(searchFilter) {
    connector.logmsg("selectEntries called with filter: " + searchFilter);

    // Reset iterator
    rowIterator = sheet.iterator();
    currentRowNum = 0;

    // Skip header if configured
    if (connector.getParam("skipHeader") == "true" && rowIterator.hasNext()) {
        rowIterator.next();
        currentRowNum++;
    }

    // Handle start row
    var startRow = parseInt(connector.getParam("startRow") || "0");
    while (currentRowNum < startRow && rowIterator.hasNext()) {
        rowIterator.next();
        currentRowNum++;
    }
}

function getNextEntry() {
    entry.removeAllAttributes();

    // Check end row limit
    var endRow = parseInt(connector.getParam("endRow") || "-1");
    if (endRow >= 0 && currentRowNum > endRow) {
        result.setStatus(0);
        result.setMessage("End row reached");
        return;
    }

    if (!rowIterator.hasNext()) {
        result.setStatus(0);
        result.setMessage("End of input");
        return;
    }

    try {
        var row = rowIterator.next();
        currentRowNum++;

        // Add row number as special attribute
        entry.setAttribute("$rowNumber", row.getRowNum().toString());

        // Process each mapped column
        var keys = columnMap.keySet().toArray();
        for (var i = 0; i < keys.length; i++) {
            var colLetter = keys[i];
            var attrName = columnMap.get(colLetter);
            var colIndex = getColumnIndex(colLetter);

            if (colIndex >= 0) {
                var cell = row.getCell(colIndex);
                var cellValue = getCellValue(cell);

                if (cellValue != null && cellValue != "") {
                    entry.setAttribute(attrName, cellValue);
                }
            }
        }

        // Add unique key as $dn for linking
        if (uniqueKeyColumn != null) {
            var keyColIndex = getColumnIndex(uniqueKeyColumn);
            var keyCell = row.getCell(keyColIndex);
            var keyValue = getCellValue(keyCell);
            if (keyValue != null) {
                entry.setAttribute("$dn", keyValue);
            }
        } else {
            entry.setAttribute("$dn", row.getRowNum().toString());
        }

        result.setStatus(1);

    } catch (e) {
        connector.logmsg("Error reading row: " + e);
        result.setStatus(0);
        result.setMessage("Error: " + e);
    }
}

function putEntry() {
    connector.logmsg("putEntry called");

    try {
        var writeMode = connector.getParam("writeMode") || "append";

        if (writeMode == "append") {
            // Add new row at the end
            var newRowNum = sheet.getLastRowNum() + 1;
            var row = sheet.createRow(newRowNum);

            // Write each attribute to its mapped column
            var keys = columnMap.keySet().toArray();
            for (var i = 0; i < keys.length; i++) {
                var colLetter = keys[i];
                var attrName = columnMap.get(colLetter);
                var colIndex = getColumnIndex(colLetter);

                if (entry.getAttribute(attrName) != null) {
                    var cell = row.createCell(colIndex);
                    var value = entry.getString(attrName);
                    cell.setCellValue(value);
                }
            }

            connector.logmsg("Added new row at position: " + newRowNum);

        } else if (writeMode == "overwrite") {
            throw new java.lang.Exception("Overwrite mode not supported in putEntry. Use modEntry instead.");
        }

        // Save workbook
        var filePath = connector.getParam("excelFilePath");
        var fileOutputStream = new FileOutputStream(filePath);
        workbook.write(fileOutputStream);
        fileOutputStream.close();

        result.setStatus(1);

    } catch (e) {
        connector.logmsg("Error in putEntry: " + e);
        result.setStatus(0);
        result.setMessage("Error: " + e);
        throw e;
    }
}

function modEntry() {
    connector.logmsg("modEntry called");

    try {
        // Build row cache if not already built
        if (rowCache == null) {
            buildRowCache();
        }

        // Get unique key value from entry
        var keyValue;
        if (uniqueKeyColumn != null) {
            var keyAttr = columnMap.get(uniqueKeyColumn);
            keyValue = entry.getString(keyAttr);
        } else {
            keyValue = entry.getString("$rowNumber");
        }

        if (keyValue == null) {
            throw new java.lang.Exception("Cannot modify entry: unique key value not found");
        }

        // Find the row
        var row = rowCache.get(keyValue);
        if (row == null) {
            throw new java.lang.Exception("Row not found for key: " + keyValue);
        }

        // Update each attribute
        var keys = columnMap.keySet().toArray();
        for (var i = 0; i < keys.length; i++) {
            var colLetter = keys[i];
            var attrName = columnMap.get(colLetter);
            var colIndex = getColumnIndex(colLetter);

            if (entry.getAttribute(attrName) != null) {
                var cell = row.getCell(colIndex);
                if (cell == null) {
                    cell = row.createCell(colIndex);
                }
                var value = entry.getString(attrName);
                cell.setCellValue(value);
            }
        }

        connector.logmsg("Modified row: " + row.getRowNum());

        // Save workbook
        var filePath = connector.getParam("excelFilePath");
        var fileOutputStream = new FileOutputStream(filePath);
        workbook.write(fileOutputStream);
        fileOutputStream.close();

        result.setStatus(1);

    } catch (e) {
        connector.logmsg("Error in modEntry: " + e);
        result.setStatus(0);
        result.setMessage("Error: " + e);
        throw e;
    }
}

function deleteEntry() {
    connector.logmsg("deleteEntry called");

    try {
        // Build row cache if not already built
        if (rowCache == null) {
            buildRowCache();
        }

        // Get unique key value from entry
        var keyValue;
        if (uniqueKeyColumn != null) {
            var keyAttr = columnMap.get(uniqueKeyColumn);
            keyValue = entry.getString(keyAttr);
        } else {
            keyValue = entry.getString("$rowNumber");
        }

        if (keyValue == null) {
            throw new java.lang.Exception("Cannot delete entry: unique key value not found");
        }

        // Find the row
        var row = rowCache.get(keyValue);
        if (row == null) {
            throw new java.lang.Exception("Row not found for key: " + keyValue);
        }

        // Remove the row (shifts subsequent rows up)
        var rowNum = row.getRowNum();
        sheet.removeRow(row);

        // Shift rows up if not the last row
        if (rowNum < sheet.getLastRowNum()) {
            sheet.shiftRows(rowNum + 1, sheet.getLastRowNum(), -1);
        }

        connector.logmsg("Deleted row: " + rowNum);

        // Save workbook
        var filePath = connector.getParam("excelFilePath");
        var fileOutputStream = new FileOutputStream(filePath);
        workbook.write(fileOutputStream);
        fileOutputStream.close();

        // Rebuild cache after deletion
        rowCache = null;

        result.setStatus(1);

    } catch (e) {
        connector.logmsg("Error in deleteEntry: " + e);
        result.setStatus(0);
        result.setMessage("Error: " + e);
        throw e;
    }
}

function findEntry() {
    connector.logmsg("findEntry called");

    try {
        // Build row cache if not already built
        if (rowCache == null) {
            buildRowCache();
        }

        var searchResults = new java.util.HashMap();

        // Check if searching by unique key
        if (search.size() == 1) {
            var criteria = search.getCriteria(0);
            var searchAttr = criteria.name;
            var searchValue = criteria.value;

            // Check if searching by the unique key attribute
            var uniqueKeyAttr = null;
            if (uniqueKeyColumn != null) {
                uniqueKeyAttr = columnMap.get(uniqueKeyColumn);
            }

            if (searchAttr == uniqueKeyAttr || searchAttr == "$dn" || searchAttr == "$rowNumber") {
                // Direct lookup by key
                var row = rowCache.get(searchValue);
                if (row != null) {
                    var foundEntry = system.newEntry();

                    // Add row number
                    foundEntry.setAttribute("$rowNumber", row.getRowNum().toString());

                    // Process each mapped column
                    var keys = columnMap.keySet().toArray();
                    for (var i = 0; i < keys.length; i++) {
                        var colLetter = keys[i];
                        var attrName = columnMap.get(colLetter);
                        var colIndex = getColumnIndex(colLetter);

                        var cell = row.getCell(colIndex);
                        var cellValue = getCellValue(cell);

                        if (cellValue != null && cellValue != "") {
                            foundEntry.setAttribute(attrName, cellValue);
                        }
                    }

                    foundEntry.setAttribute("$dn", searchValue);
                    searchResults.put(searchValue, foundEntry);
                }
            }
        }

        // If no direct key match, iterate through all rows
        if (searchResults.size() == 0) {
            var iter = sheet.iterator();

            // Skip header if configured
            if (connector.getParam("skipHeader") == "true" && iter.hasNext()) {
                iter.next();
            }

            while (iter.hasNext()) {
                var row = iter.next();
                var foundEntry = system.newEntry();
                var matches = true;

                // Add row number
                foundEntry.setAttribute("$rowNumber", row.getRowNum().toString());

                // Process each mapped column
                var keys = columnMap.keySet().toArray();
                for (var i = 0; i < keys.length; i++) {
                    var colLetter = keys[i];
                    var attrName = columnMap.get(colLetter);
                    var colIndex = getColumnIndex(colLetter);

                    var cell = row.getCell(colIndex);
                    var cellValue = getCellValue(cell);

                    if (cellValue != null && cellValue != "") {
                        foundEntry.setAttribute(attrName, cellValue);
                    }
                }

                // Check if entry matches search criteria
                for (var i = 0; i < search.size(); i++) {
                    var criteria = search.getCriteria(i);
                    var attrValue = foundEntry.getString(criteria.name);

                    if (criteria.match == search.EXACT) {
                        if (attrValue != criteria.value) {
                            matches = false;
                            break;
                        }
                    } else if (criteria.match == search.CONTAINS) {
                        if (attrValue == null || attrValue.indexOf(criteria.value) < 0) {
                            matches = false;
                            break;
                        }
                    }
                }

                if (matches) {
                    var keyValue;
                    if (uniqueKeyColumn != null) {
                        var keyColIndex = getColumnIndex(uniqueKeyColumn);
                        var keyCell = row.getCell(keyColIndex);
                        keyValue = getCellValue(keyCell);
                    } else {
                        keyValue = row.getRowNum().toString();
                    }

                    foundEntry.setAttribute("$dn", keyValue);
                    searchResults.put(keyValue, foundEntry);
                }
            }
        }

        // Return results
        entry.removeAllAttributes();
        var keys = searchResults.keySet().toArray();

        if (keys.length == 0) {
            result.setStatus(0);
            result.setMessage("No entries found");
        } else if (keys.length == 1) {
            result.setStatus(1);
            entry.merge(searchResults.get(keys[0]));
        } else {
            result.setStatus(0);
            java.util.Arrays.sort(keys);
            for (var i = 0; i < keys.length; i++) {
                connector.addFindEntry(searchResults.get(keys[i]));
            }
        }

    } catch (e) {
        connector.logmsg("Error in findEntry: " + e);
        result.setStatus(0);
        result.setMessage("Error: " + e);
    }
}

function querySchema() {
    connector.logmsg("querySchema called");

    try {
        // Return schema based on column mappings
        var keys = columnMap.keySet().toArray();
        for (var i = 0; i < keys.length; i++) {
            var colLetter = keys[i];
            var attrName = columnMap.get(colLetter);

            var schemaEntry = new com.ibm.di.entry.Entry();
            schemaEntry.addAttributeValue("name", attrName);
            schemaEntry.addAttributeValue("syntax", "String");
            list.add(schemaEntry);
        }

        // Add special attributes
        var rowNumEntry = new com.ibm.di.entry.Entry();
        rowNumEntry.addAttributeValue("name", "$rowNumber");
        rowNumEntry.addAttributeValue("syntax", "String");
        list.add(rowNumEntry);

        var dnEntry = new com.ibm.di.entry.Entry();
        dnEntry.addAttributeValue("name", "$dn");
        dnEntry.addAttributeValue("syntax", "String");
        list.add(dnEntry);

        result.setStatus(1);

    } catch (e) {
        connector.logmsg("Error in querySchema: " + e);
        result.setStatus(0);
    }
}

function terminate() {
    connector.logmsg("Terminating Excel XLSX Connector...");

    try {
        if (workbook != null) {
            workbook.close();
            workbook = null;
        }

        sheet = null;
        rowIterator = null;
        columnMap = null;
        rowCache = null;

        connector.logmsg("Excel XLSX Connector terminated successfully");

    } catch (e) {
        connector.logmsg("Error terminating connector: " + e);
    }
}

// 20260520 1514 Fixed deleteEntry(), possible putEntry and modEntry too, by changing conn to entry
// 20260530 1531 All modes should be working (in theory) - still testing
// 20260531 1631 Added case sensitivity checkbox for Link Criteria

// Excel XLSX Connector
// Supports reading and writing Excel .xlsx files using Apache POI
// Unique Key Strategy: Uses specified column or row number as unique identifier

// TODO:
// 1. setting to control if XLS or XLSX is created upon output

// FIX:
// 1. modEntry() changing the wrong row

importPackage(Packages.org.apache.poi.xssf.usermodel);
importPackage(Packages.org.apache.poi.hssf.usermodel);
importPackage(Packages.org.apache.poi.ss.usermodel);
importPackage(Packages.org.apache.poi.ss.util);
importPackage(Packages.java.io);
importPackage(Packages.java.util);
importPackage(Packages.java.text);

// Global variables
var __workbook          = null;
var __sheet             = null;
var __rowIterator       = null;
var __currentRowNum     = 0;
var __columnMap         = null;
var __columnMapFromHeader = false; // true when column map was derived from header row
var __uniqueKeyColumn   = null;
var __dataFormatter     = null;
var __evaluator         = null;
var __rowCache          = null;    // null so lazy-build checks fire correctly
var __rowCacheUIDs       = null;    // null so lazy-build checks fire correctly
var __rowCacheRowNumbers = null;    // null so lazy-build checks fire correctly


// Internal logmsg — accommodates calling from Connector Schema (Connect + Next)
function logmsg(lvl, msg) {
	if (typeof msg == "undefined") {
		msg = lvl;
		lvl = "INFO";
	}
	main.logmsg(lvl, msg);
	java.lang.System.out.println(lvl + " " + msg);
}

// Helper: convert column letter(s) to zero-based index
function getColumnIndex(letter) {
	if (!letter || letter == "") return -1;
	letter = letter.toUpperCase();
	var index = 0;
	for (var i = 0; i < letter.length; i++) {
		index = index * 26 + (letter.charCodeAt(i) - 64);
	}
	return index - 1;
}

// Helper: convert zero-based column index to letter(s)
function getColumnLetter(index) {
	var letter = "";
	while (index >= 0) {
		letter = String.fromCharCode(65 + (index % 26)) + letter;
		index  = Math.floor(index / 26) - 1;
	}
	return letter;
}

// Helper: increment a column letter (e.g. "A" -> "B", "Z" -> "AA")
function incrementColumn(col) {
	var chars = col.split('');
	var i     = chars.length - 1;
	while (i >= 0) {
		if (chars[i] < 'Z') {
			chars[i] = String.fromCharCode(chars[i].charCodeAt(0) + 1);
			return chars.join('');
		}
		chars[i] = 'A';
		i--;
	}
	return 'A' + chars.join('');
}

// Handles all ConnectorInterface exceptions
function handleCIException(methodThrowingException, exception) {
	var msg = "ERROR during " + methodThrowingException + "() operation: " + exception;
	logmsg("ERROR", msg);
	result.setStatus(0);
	result.setMessage(exception);
	throw new java.lang.Exception(msg)
}

// Parse column mappings from configuration string ("A:firstName,B:lastName,...")
function parseColumnMappings(mappingString) {
	var result = new java.util.LinkedHashMap();
	if (!mappingString || mappingString == "") {
		return result;
	}
	var mappings = mappingString.split(",");
	for (var i = 0; i < mappings.length; i++) {
		var parts = mappings[i].trim().split(":");
		if (parts.length == 2) {
			result.put(parts[0].trim().toUpperCase(), parts[1].trim());
		}
	}
	return result;
}

// Get cell value handling all cell types
function getCellValue(cell) {
	if (cell == null) return null;
	try {
		// NOTE: do not call cellType.toString() — that produces a string like "1"
		// which never matches the integer constants (CELL_TYPE_STRING etc.)
		var cellType = cell.getCellType();
		switch (cellType) {
			case cell.CELL_TYPE_STRING:
				return cell.getStringCellValue();
			case cell.CELL_TYPE_NUMERIC:
				if (DateUtil.isCellDateFormatted(cell)) {
					var dateValue     = cell.getDateCellValue();
					var dateFormatStr = connector.getParam("dateFormat");
					if (dateFormatStr && dateFormatStr != "") {
						return new java.text.SimpleDateFormat(dateFormatStr).format(dateValue);
					}
					return dateValue.toString();
				}
				return cell.getNumericCellValue().toString();
			case cell.CELL_TYPE_BOOLEAN:
				return cell.getBooleanCellValue().toString();
			case cell.CELL_TYPE_FORMULA:
				try {
					return __dataFormatter.formatCellValue(cell, __evaluator);
				} catch (e) {
					return cell.getCellFormula();
				}
			case cell.CELL_TYPE_BLANK:
				return null;
			default:
				return __dataFormatter.formatCellValue(cell);
		}
	} catch (e) {
		logmsg("ERROR", "Error getting cell value: " + e);
		return null;
	}
}

// Save workbook back to disk
function saveWorkbook() {
	var filePath = connector.getParam("excelFilePath");
	var fos      = new java.io.FileOutputStream(filePath);
	__workbook.write(fos);
	fos.close();
}

// Return the __rowCache value associated with the passed key
function returnRowCacheEntry(key_UID_or_LineNum) {
	// See if its a configured index column
	var foundOne = __rowCache.get(key_UID_or_LineNum);
	if (!foundOne) {
		// If not, check for $uid or $rowNumber
		var actualKey = __rowCacheUIDs.get(key_UID_or_LineNum) || __rowCacheRowNumbers.get(key_UID_or_LineNum);
		foundOne = __rowCache.get(actualKey)
	}
}

// Build row cache (key -> Row) for fast lookup in findEntry/modEntry/deleteEntry
function buildRowCache() {
	__rowCache = new java.util.HashMap();
	__rowCacheUIDS = new java.util.HashMap();
	__rowCacheRowNumbers = new java.util.HashMap();

	var iter   = __sheet.iterator();

	if (connector.getParam("skipHeader") == "true" || __columnMapFromHeader) {
		if (iter.hasNext()) iter.next();
	}

	var uniqueKeyColIndex = getColumnIndex(__uniqueKeyColumn);

	while (iter.hasNext()) {
		var row      = iter.next();
		var rowNum = row.getRowNum().toString();
		var uidCellValue = null;
		if (uniqueKeyColIndex >= 0) {
			uidCellValue = getCellValue(row.getCell(uniqueKeyColIndex));
		}
		var keyValue = (uniqueKeyColIndex >= 0)
			? uidCellValue
			: rowNum;
		if (keyValue != null) {
			__rowCache.put(keyValue, row);
			__rowCacheRowNumbers.put(rowNum, keyValue);
			__rowCacheUIDS.put(uidCellValue, keyValue)
		}
	}
	logmsg("Built row cache with " + __rowCache.size() + " entries");
}

function initialize() {
	logmsg("Initializing Excel XLSX Connector...");
	try {
		var filePath   = connector.getParam("excelFilePath");
		var sheetName  = connector.getParam("sheetName");
		var sheetIndex = connector.getParam("sheetIndex");

		if (!filePath || filePath == "") {
			throw new java.lang.Exception("Excel file path is required");
		}

		__uniqueKeyColumn = connector.getParam("uniqueKeyColumn") || null;
		if (__uniqueKeyColumn == "") __uniqueKeyColumn = null;

		if (__uniqueKeyColumn) {
			logmsg("Using column " + __uniqueKeyColumn + " as unique key");
		} else {
			logmsg("No unique key column specified, using row number");
		}

		var file = new java.io.File(filePath);
		if (!file.exists()) {
			if (connector.getParam("createIfNotExists") == "true") {
				logmsg("Creating new Excel file: " + filePath);
				__workbook = new org.apache.poi.xssf.usermodel.XSSFWorkbook();
				__sheet    = __workbook.createSheet(sheetName || "Sheet1");
				saveWorkbook();
			} else {
				throw new java.lang.Exception("Excel file not found: " + filePath);
			}
		} else {
			// Detect XLSX vs XLS by magic bytes rather than file extension
			var fis    = new java.io.FileInputStream(file);
			var header = java.lang.reflect.Array.newInstance(java.lang.Byte.TYPE, 4);
			fis.read(header);
			fis.close();

			fis = new java.io.FileInputStream(file);
			// XLSX is a ZIP file — magic bytes PK (0x50 0x4B)
			if ((header[0] & 0xFF) == 0x50 && (header[1] & 0xFF) == 0x4B) {
				__workbook = new org.apache.poi.xssf.usermodel.XSSFWorkbook(fis);
			// XLS is OLE2 — magic bytes 0xD0 0xCF
			} else if ((header[0] & 0xFF) == 0xD0 && (header[1] & 0xFF) == 0xCF) {
				__workbook = new org.apache.poi.hssf.usermodel.HSSFWorkbook(fis);
			} else {
				throw new java.lang.Exception("Unrecognised file format: " + filePath);
			}
			fis.close();

			if (sheetName && sheetName != "") {
				__sheet = __workbook.getSheet(sheetName);
				if (__sheet == null) {
					throw new java.lang.Exception("Sheet not found: " + sheetName);
				}
			} else {
				var idx = parseInt(sheetIndex || "0");
				if (idx < 0 || idx >= __workbook.getNumberOfSheets()) {
					throw new java.lang.Exception("Invalid sheet index: " + idx);
				}
				__sheet = __workbook.getSheetAt(idx);
			}
		}

		__dataFormatter = new org.apache.poi.ss.usermodel.DataFormatter();
		__evaluator     = __workbook.getCreationHelper().createFormulaEvaluator();

		// Resolve column map — connector parameter takes priority, header row is the fallback
		__columnMap = parseColumnMappings(connector.getParam("columnMappings"));

		if (__columnMap.size() > 0) {
			__columnMapFromHeader = false;
			logmsg("Column map from connector parameters: " + __columnMap.size() + " columns");
		} else {
			// No mappings configured — read row 0 directly using sheet.getRow()
			// so no iterator is consumed here
			var headerRow = __sheet.getRow(0);
			if (headerRow == null) {
				throw new java.lang.Exception("No column mappings configured and sheet has no header row");
			}
			var columnLetter = "A";
			var cellIter     = headerRow.cellIterator();
			while (cellIter.hasNext()) {
				var cell  = cellIter.next();
				var value = getCellValue(cell) || "";
				__columnMap.put(columnLetter, system.splitString(value, "\n")[0]);
				columnLetter = incrementColumn(columnLetter);
			}
			__columnMapFromHeader = true;
			logmsg("Column map built from header row: " + __columnMap.size() + " columns");
		}

		logmsg("Connector initialised — sheet: " + __sheet.getSheetName() + ", rows: " + __sheet.getLastRowNum());

	} catch (e) {
		logmsg("ERROR", "Error initialising connector: " + e);
		throw e;
	}
}

function selectEntries(searchFilter) {
	logmsg("selectEntries called");

	__rowIterator   = __sheet.iterator();
	__currentRowNum = 0;

	try {
		// Advance to startRow
		var startRow = parseInt(connector.getParam("startRow") || "0");
		while (__currentRowNum < startRow && __rowIterator.hasNext()) {
			__rowIterator.next();
			__currentRowNum++;
		}
/*	
		// Skip the header row if the column map was derived from it,
		// or if explicit mappings are configured and skipHeader is set.
		// The two cases are mutually exclusive — __columnMapFromHeader
		// is only true when no connector parameter mappings were provided.
		if (__columnMapFromHeader || connector.getParam("skipHeader") == "true") {
			if (__rowIterator.hasNext()) {
				__rowIterator.next();
				__currentRowNum++;
				logmsg("Header row skipped");
			}
		}
*/

		logmsg("selectEntries ready — starting from sheet row " + __currentRowNum);
	} catch(e) {
		handleCIException("selectEntries", e)
	}
}

function getNextEntry() {
	entry.removeAllAttributes();

	var endRow = parseInt(connector.getParam("endRow") || "-1");
	if (endRow >= 0 && __currentRowNum > endRow) {
		result.setStatus(0);
		result.setMessage("End row reached");
		return;
	}

	if (!__rowIterator.hasNext()) {
		result.setStatus(0);
		result.setMessage("End of input");
		return;
	}

	try {
		var row = __rowIterator.next();
		__currentRowNum++;

		entry.merge(buildEntryFromRow(row));
		result.setStatus(1);

	} catch (e) {
		handleCIException("getNextEntry", e)
	}
}

function putEntry() {
	logmsg("putEntry called");
	try {
		var writeMode = connector.getParam("writeMode") || "append";
		if (writeMode != "append") {
			throw new java.lang.Exception("Only 'append' writeMode is supported in putEntry");
		}

		var newRowNum = __sheet.getLastRowNum() + 1;
		var row       = __sheet.createRow(newRowNum);
		var keys      = __columnMap.keySet().toArray();

		for (var i = 0; i < keys.length; i++) {
			var colLetter = keys[i];
			var attrName  = __columnMap.get(colLetter);
			var colIndex  = getColumnIndex(colLetter);
			if (entry.getAttribute(attrName) != null) {
				row.createCell(colIndex).setCellValue(entry.getString(attrName));
			}
		}

		saveWorkbook();
		logmsg("Added new row at position: " + newRowNum);
		result.setStatus(1);

	} catch (e) {
		handleCIException("putEntry", e)
	}
}

function modEntry() {
	logmsg("modEntry called");
	try {
		if (__rowCache == null) buildRowCache();

		var fromLookup = connector.getFirstFindEntry();
		if (fromLookup) {
			for (var att in fromLookup) {
				if (!entry[att.getName()]) {
					entry.setAttribute(att)
				}
			}
			//entry["$uid"] = fromLookup["$uid"]
		}

		var keyValue;
		if (__uniqueKeyColumn != null) {
			keyValue = entry.getString(__columnMap.get(__uniqueKeyColumn));
		} else {
			keyValue = entry.getString("$uid") || entry.getString("$rowNumber");
		}

		if (keyValue == null) {
			throw new java.lang.Exception("Cannot modify entry: unique key value not found in conn");
		}

		var row = __rowCache.get(keyValue);
		if (row == null) {
			throw new java.lang.Exception("Row not found for key: " + keyValue);
		}

		var keys = __columnMap.keySet().toArray();
		for (var i = 0; i < keys.length; i++) {
			var colLetter = keys[i];
			var attrName  = __columnMap.get(colLetter);
			var colIndex  = getColumnIndex(colLetter);
			if (entry.getAttribute(attrName) != null) {
				var cell = row.getCell(colIndex) || row.createCell(colIndex);
				cell.setCellValue(entry.getString(attrName));
			}
		}

		saveWorkbook();
		logmsg("Modified row: " + row.getRowNum());
		result.setStatus(1);

	} catch (e) {
		handleCIException("modEntry", e)
	}
}

function deleteEntry() {
	logmsg("deleteEntry called");
	try {
		if (__rowCache == null) buildRowCache();

		var keyValue;
		if (__uniqueKeyColumn != null) {
			keyValue = entry.getString(__columnMap.get(__uniqueKeyColumn));
		} else {
			keyValue = entry.getString("$uid") || entry.getString("$rowNumber");
		}

		if (keyValue == null) {
			throw new java.lang.Exception("Cannot delete entry: unique key value not found in conn");
		}

		var row = __rowCache.get(keyValue);
		if (row == null) {
			throw new java.lang.Exception("Row not found for key: " + keyValue);
		}

		var rowNum = row.getRowNum();
		__sheet.removeRow(row);
		if (rowNum < __sheet.getLastRowNum()) {
			__sheet.shiftRows(rowNum + 1, __sheet.getLastRowNum(), -1);
		}

		saveWorkbook();
		logmsg("Deleted row: " + rowNum);

		__rowCache = null; // Force rebuild — row numbers have shifted
		result.setStatus(1);

	} catch (e) {
		handleCIException("deleteEntry", e)
	}
}

function findEntry() {
	logmsg("findEntry called");
	try {
		connector.clearFindEntries();

		if (__rowCache == null) buildRowCache();

		var searchResults   = new java.util.ArrayList();
		var searchType      = search.getType();
		var criteriaCount   = search.size();
		var fastPathHandled = false;

		// Fast-path: single EXACT match on unique key, $uid, or $rowNumber
		if (criteriaCount == 1) {
			var crit          = search.getCriteria(0);
			var uniqueKeyAttr = (__uniqueKeyColumn != null) ? __columnMap.get(__uniqueKeyColumn) : null;

			if (crit.match == search.EXACT &&
				(crit.name == uniqueKeyAttr || crit.name == "$uid" || crit.name == "$rowNumber")) {
				fastPathHandled = true;
				var row = __rowCache.get(crit.value);
				if (row != null) {
					searchResults.add(buildEntryFromRow(row));
				}
			}
		}

		// Full scan — only if fast-path key lookup was not applicable
		if (!fastPathHandled) {
			var iter = __sheet.iterator();
			if (__columnMapFromHeader || connector.getParam("skipHeader") == "true") {
				if (iter.hasNext()) iter.next();
			}

			while (iter.hasNext()) {
				var row        = iter.next();
				var candidate  = buildEntryFromRow(row);
				var matchCount = 0;

				for (var i = 0; i < criteriaCount; i++) {
					var crit = search.getCriteria(i);
					if (evaluateCriteria(candidate.getString(crit.name), crit.match, crit.value)) {
						matchCount++;
					}
				}

				var rowMatches;
				if (searchType == search.SEARCH_OR) {
					rowMatches = (matchCount > 0);
				} else if (searchType == search.SEARCH_NOT) {
					rowMatches = (matchCount == 0);
				} else { // SEARCH_AND (default)
					rowMatches = (matchCount == criteriaCount);
				}

				if (rowMatches) {
					searchResults.add(candidate);
				}
			}
		}

		if (searchResults.size() == 0) {
			result.setStatus(0);
			result.setMessage("No entries found");
		} else {
			result.setStatus(1);
			entry.removeAllAttributes();
			entry.merge(searchResults.get(0));
			for (var i = 0; i < searchResults.size(); i++) {
				connector.addFindEntry(searchResults.get(i));
			}
		}

	} catch (e) {
		handleCIException("findEntry", e)
	}
}

// Build an Entry from a POI Row using the current column map.
// Always sets every mapped attribute — blank cells write empty string
// to prevent value carry-over from the previous row via entry.merge().
function buildEntryFromRow(row) {
	var e    = system.newEntry();
	var keys = __columnMap.keySet().toArray();

	e.setAttribute("$rowNumber", row.getRowNum().toString());

	for (var i = 0; i < keys.length; i++) {
		var colLetter = keys[i];
		var attrName  = __columnMap.get(colLetter);
		var colIndex  = getColumnIndex(colLetter);
		var cellValue = getCellValue(row.getCell(colIndex));
		e.setAttribute(attrName, cellValue != null ? cellValue : "");
	}

	var dn = (__uniqueKeyColumn != null)
		? getCellValue(row.getCell(getColumnIndex(__uniqueKeyColumn)))
		: row.getRowNum().toString();
	e.setAttribute("$uid", dn);

	return e;
}

// Convert the value passed to a Float if possible
function numOrText(val, otherVal) {
	if (typeof(otherVal) == "string") {
		return String(val).trim()
	}

	try {
		var newVal = java.lang.Float(val);
		return newVal
	} catch(ex) {
		return val
	}
}

function evaluateCriteria(attrValue, matchType, searchValue) {
	if (attrValue == null) return false;

	var caseSensitive	= connector.getParam("caseSensitiveSearch");
	var a = numOrText(attrValue.toString());
	var s = numOrText((searchValue != null) ? searchValue.toString() : "", a);
	if (caseSensitive) {
		a = a.toUpperCase();
		s = s.toUpperCase()
	}


	if (matchType == search.EXACT)                 return a == s;
	if (matchType == search.NOT_STRING)            return a != s;
	if (matchType == search.SUBSTRING)             return a.indexOf(s) >= 0;
	if (matchType == search.INITIAL_STRING)        return a.indexOf(s) == 0;
	if (matchType == search.FINAL_STRING)          return a.length >= s.length && a.lastIndexOf(s) == a.length - s.length;

	if (matchType == search.LESS_THAN)             return a < s;
	if (matchType == search.LESS_THAN_OR_EQUAL)    return a <= s;
	if (matchType == search.GREATER_THAN)          return a > s;
	if (matchType == search.GREATER_THAN_OR_EQUAL) return a >= s;
/*
	if (matchType == search.LESS_THAN)             return parseFloat(a) < parseFloat(s);
	if (matchType == search.LESS_THAN_OR_EQUAL)    return parseFloat(a) <= parseFloat(s);
	if (matchType == search.GREATER_THAN)          return parseFloat(a) > parseFloat(s);
	if (matchType == search.GREATER_THAN_OR_EQUAL) return parseFloat(a) >= parseFloat(s);
*/
	logmsg("WARN", "evaluateCriteria: unhandled match type " + matchType);
	return false;
}

function querySchema() {
	logmsg("querySchema called");
	try {
		var keys = __columnMap.keySet().toArray();
		for (var i = 0; i < keys.length; i++) {
			var schemaEntry = system.newEntry();
			schemaEntry.addAttributeValue("name", __columnMap.get(keys[i]));
			schemaEntry.addAttributeValue("syntax", "String");
			list.add(schemaEntry);
		}

		var rowNumEntry = system.newEntry();
		rowNumEntry.addAttributeValue("name", "$rowNumber");
		rowNumEntry.addAttributeValue("syntax", "String");
		list.add(rowNumEntry);

		var dnEntry = system.newEntry();
		dnEntry.addAttributeValue("name", "$uid");
		dnEntry.addAttributeValue("syntax", "String");
		list.add(dnEntry);

		result.setStatus(1);

	} catch (e) {
		handleCIException("querySchema", e)
	}
}

function terminate() {
	logmsg("Terminating Excel XLSX Connector...");
	try {
		if (__workbook != null) {
			__workbook.close();
		}
	} catch (e) {
		logmsg("WARN", "Error closing workbook: " + e);
	} finally {
		__workbook            = null;
		__sheet               = null;
		__rowIterator         = null;
		__columnMap           = null;
		__columnMapFromHeader = false;
		__rowCache            = null;
		__evaluator           = null;
		__dataFormatter       = null;
		logmsg("Excel XLSX Connector terminated");
	}
}

// 20260520 1514 Fixed deleteEntry(), possible putEntry and modEntry too, by changing conn to entry
// 20260530 1531 All modes should be working (in theory) - still testing
// 20260531 1631 Added case sensitivity checkbox for Link Criteria
// 20260602 1430 Connector passed test AL, publishing to github and sharing with the community

// Excel XLSX Connector
// Supports reading and writing Excel .xlsx files using Apache POI
// Unique Key Strategy: Uses specified column or row number as unique identifier

// TODO:
// 1. setting to control if XLS or XLSX is created upon output

// FIX:
// 1. modEntry() changing the wrong row

importPackage(Packages.org.apache.poi.xssf.usermodel);
importPackage(Packages.org.apache.poi.hssf.usermodel);
importPackage(Packages.org.apache.poi.ss.usermodel);
importPackage(Packages.org.apache.poi.ss.util);
importPackage(Packages.java.io);
importPackage(Packages.java.util);
importPackage(Packages.java.text);

// Global variables
var __workbook          = null;
var __sheet             = null;
var __rowIterator       = null;
var __currentRowNum     = 0;
var __columnMap         = null;
var __columnMapFromHeader = false; // true when column map was derived from header row
var __uniqueKeyColumn   = null;
var __dataFormatter     = null;
var __evaluator         = null;
var __rowCache          = null;    // null so lazy-build checks fire correctly
var __rowCacheUIDs       = null;    // null so lazy-build checks fire correctly
var __rowCacheRowNumbers = null;    // null so lazy-build checks fire correctly


// Internal logmsg — accommodates calling from Connector Schema (Connect + Next)
function logmsg(lvl, msg) {
	if (typeof msg == "undefined") {
		msg = lvl;
		lvl = "INFO";
	}
	main.logmsg(lvl, msg);
	java.lang.System.out.println(lvl + " " + msg);
}

// Helper: convert column letter(s) to zero-based index
function getColumnIndex(letter) {
	if (!letter || letter == "") return -1;
	letter = letter.toUpperCase();
	var index = 0;
	for (var i = 0; i < letter.length; i++) {
		index = index * 26 + (letter.charCodeAt(i) - 64);
	}
	return index - 1;
}

// Helper: convert zero-based column index to letter(s)
function getColumnLetter(index) {
	var letter = "";
	while (index >= 0) {
		letter = String.fromCharCode(65 + (index % 26)) + letter;
		index  = Math.floor(index / 26) - 1;
	}
	return letter;
}

// Helper: increment a column letter (e.g. "A" -> "B", "Z" -> "AA")
function incrementColumn(col) {
	var chars = col.split('');
	var i     = chars.length - 1;
	while (i >= 0) {
		if (chars[i] < 'Z') {
			chars[i] = String.fromCharCode(chars[i].charCodeAt(0) + 1);
			return chars.join('');
		}
		chars[i] = 'A';
		i--;
	}
	return 'A' + chars.join('');
}

// Handles all ConnectorInterface exceptions
function handleCIException(methodThrowingException, exception) {
	var msg = "ERROR during " + methodThrowingException + "() operation: " + exception;
	logmsg("ERROR", msg);
	result.setStatus(0);
	result.setMessage(exception);
	throw new java.lang.Exception(msg)
}

// Parse column mappings from configuration string ("A:firstName,B:lastName,...")
function parseColumnMappings(mappingString) {
	var result = new java.util.LinkedHashMap();
	if (!mappingString || mappingString == "") {
		return result;
	}
	var mappings = mappingString.split(",");
	for (var i = 0; i < mappings.length; i++) {
		var parts = mappings[i].trim().split(":");
		if (parts.length == 2) {
			result.put(parts[0].trim().toUpperCase(), parts[1].trim());
		}
	}
	return result;
}

// Get cell value handling all cell types
function getCellValue(cell) {
	if (cell == null) return null;
	try {
		// NOTE: do not call cellType.toString() — that produces a string like "1"
		// which never matches the integer constants (CELL_TYPE_STRING etc.)
		var cellType = cell.getCellType();
		switch (cellType) {
			case cell.CELL_TYPE_STRING:
				return cell.getStringCellValue();
			case cell.CELL_TYPE_NUMERIC:
				if (DateUtil.isCellDateFormatted(cell)) {
					var dateValue     = cell.getDateCellValue();
					var dateFormatStr = connector.getParam("dateFormat");
					if (dateFormatStr && dateFormatStr != "") {
						return new java.text.SimpleDateFormat(dateFormatStr).format(dateValue);
					}
					return dateValue.toString();
				}
				return cell.getNumericCellValue().toString();
			case cell.CELL_TYPE_BOOLEAN:
				return cell.getBooleanCellValue().toString();
			case cell.CELL_TYPE_FORMULA:
				try {
					return __dataFormatter.formatCellValue(cell, __evaluator);
				} catch (e) {
					return cell.getCellFormula();
				}
			case cell.CELL_TYPE_BLANK:
				return null;
			default:
				return __dataFormatter.formatCellValue(cell);
		}
	} catch (e) {
		logmsg("ERROR", "Error getting cell value: " + e);
		return null;
	}
}

// Save workbook back to disk
function saveWorkbook() {
	var filePath = connector.getParam("excelFilePath");
	var fos      = new java.io.FileOutputStream(filePath);
	__workbook.write(fos);
	fos.close();
}

// Return the __rowCache value associated with the passed key
function returnRowCacheEntry(key_UID_or_LineNum) {
	// See if its a configured index column
	var foundOne = __rowCache.get(key_UID_or_LineNum);
	if (!foundOne) {
		// If not, check for $uid or $rowNumber
		var actualKey = __rowCacheUIDs.get(key_UID_or_LineNum) || __rowCacheRowNumbers.get(key_UID_or_LineNum);
		foundOne = __rowCache.get(actualKey)
	}
}

// Build row cache (key -> Row) for fast lookup in findEntry/modEntry/deleteEntry
function buildRowCache() {
	__rowCache = new java.util.HashMap();
	__rowCacheUIDS = new java.util.HashMap();
	__rowCacheRowNumbers = new java.util.HashMap();

	var iter   = __sheet.iterator();

	if (connector.getParam("skipHeader") == "true" || __columnMapFromHeader) {
		if (iter.hasNext()) iter.next();
	}

	var uniqueKeyColIndex = getColumnIndex(__uniqueKeyColumn);

	while (iter.hasNext()) {
		var row      = iter.next();
		var rowNum = row.getRowNum().toString();
		var uidCellValue = null;
		if (uniqueKeyColIndex >= 0) {
			uidCellValue = getCellValue(row.getCell(uniqueKeyColIndex));
		}
		var keyValue = (uniqueKeyColIndex >= 0)
			? uidCellValue
			: rowNum;
		if (keyValue != null) {
			__rowCache.put(keyValue, row);
			__rowCacheRowNumbers.put(rowNum, keyValue);
			__rowCacheUIDS.put(uidCellValue, keyValue)
		}
	}
	logmsg("Built row cache with " + __rowCache.size() + " entries");
}

function initialize() {
	logmsg("Initializing Excel XLSX Connector...");
	try {
		var filePath   = connector.getParam("excelFilePath");
		var sheetName  = connector.getParam("sheetName");
		var sheetIndex = connector.getParam("sheetIndex");

		if (!filePath || filePath == "") {
			throw new java.lang.Exception("Excel file path is required");
		}

		__uniqueKeyColumn = connector.getParam("uniqueKeyColumn") || null;
		if (__uniqueKeyColumn == "") __uniqueKeyColumn = null;

		if (__uniqueKeyColumn) {
			logmsg("Using column " + __uniqueKeyColumn + " as unique key");
		} else {
			logmsg("No unique key column specified, using row number");
		}

		var file = new java.io.File(filePath);
		if (!file.exists()) {
			if (connector.getParam("createIfNotExists") == "true") {
				logmsg("Creating new Excel file: " + filePath);
				__workbook = new org.apache.poi.xssf.usermodel.XSSFWorkbook();
				__sheet    = __workbook.createSheet(sheetName || "Sheet1");
				saveWorkbook();
			} else {
				throw new java.lang.Exception("Excel file not found: " + filePath);
			}
		} else {
			// Detect XLSX vs XLS by magic bytes rather than file extension
			var fis    = new java.io.FileInputStream(file);
			var header = java.lang.reflect.Array.newInstance(java.lang.Byte.TYPE, 4);
			fis.read(header);
			fis.close();

			fis = new java.io.FileInputStream(file);
			// XLSX is a ZIP file — magic bytes PK (0x50 0x4B)
			if ((header[0] & 0xFF) == 0x50 && (header[1] & 0xFF) == 0x4B) {
				__workbook = new org.apache.poi.xssf.usermodel.XSSFWorkbook(fis);
			// XLS is OLE2 — magic bytes 0xD0 0xCF
			} else if ((header[0] & 0xFF) == 0xD0 && (header[1] & 0xFF) == 0xCF) {
				__workbook = new org.apache.poi.hssf.usermodel.HSSFWorkbook(fis);
			} else {
				throw new java.lang.Exception("Unrecognised file format: " + filePath);
			}
			fis.close();

			if (sheetName && sheetName != "") {
				__sheet = __workbook.getSheet(sheetName);
				if (__sheet == null) {
					throw new java.lang.Exception("Sheet not found: " + sheetName);
				}
			} else {
				var idx = parseInt(sheetIndex || "0");
				if (idx < 0 || idx >= __workbook.getNumberOfSheets()) {
					throw new java.lang.Exception("Invalid sheet index: " + idx);
				}
				__sheet = __workbook.getSheetAt(idx);
			}
		}

		__dataFormatter = new org.apache.poi.ss.usermodel.DataFormatter();
		__evaluator     = __workbook.getCreationHelper().createFormulaEvaluator();

		// Resolve column map — connector parameter takes priority, header row is the fallback
		__columnMap = parseColumnMappings(connector.getParam("columnMappings"));

		if (__columnMap.size() > 0) {
			__columnMapFromHeader = false;
			logmsg("Column map from connector parameters: " + __columnMap.size() + " columns");
		} else {
			// No mappings configured — read row 0 directly using sheet.getRow()
			// so no iterator is consumed here
			var headerRow = __sheet.getRow(0);
			if (headerRow == null) {
				throw new java.lang.Exception("No column mappings configured and sheet has no header row");
			}
			var columnLetter = "A";
			var cellIter     = headerRow.cellIterator();
			while (cellIter.hasNext()) {
				var cell  = cellIter.next();
				var value = getCellValue(cell) || "";
				__columnMap.put(columnLetter, system.splitString(value, "\n")[0]);
				columnLetter = incrementColumn(columnLetter);
			}
			__columnMapFromHeader = true;
			logmsg("Column map built from header row: " + __columnMap.size() + " columns");
		}

		logmsg("Connector initialised — sheet: " + __sheet.getSheetName() + ", rows: " + __sheet.getLastRowNum());

	} catch (e) {
		logmsg("ERROR", "Error initialising connector: " + e);
		throw e;
	}
}

function selectEntries(searchFilter) {
	logmsg("selectEntries called");

	__rowIterator   = __sheet.iterator();
	__currentRowNum = 0;

	try {
		// Advance to startRow
		var startRow = parseInt(connector.getParam("startRow") || "0");
		while (__currentRowNum < startRow && __rowIterator.hasNext()) {
			__rowIterator.next();
			__currentRowNum++;
		}
/*	
		// Skip the header row if the column map was derived from it,
		// or if explicit mappings are configured and skipHeader is set.
		// The two cases are mutually exclusive — __columnMapFromHeader
		// is only true when no connector parameter mappings were provided.
		if (__columnMapFromHeader || connector.getParam("skipHeader") == "true") {
			if (__rowIterator.hasNext()) {
				__rowIterator.next();
				__currentRowNum++;
				logmsg("Header row skipped");
			}
		}
*/

		logmsg("selectEntries ready — starting from sheet row " + __currentRowNum);
	} catch(e) {
		handleCIException("selectEntries", e)
	}
}

function getNextEntry() {
	entry.removeAllAttributes();

	var endRow = parseInt(connector.getParam("endRow") || "-1");
	if (endRow >= 0 && __currentRowNum > endRow) {
		result.setStatus(0);
		result.setMessage("End row reached");
		return;
	}

	if (!__rowIterator.hasNext()) {
		result.setStatus(0);
		result.setMessage("End of input");
		return;
	}

	try {
		var row = __rowIterator.next();
		__currentRowNum++;

		entry.merge(buildEntryFromRow(row));
		result.setStatus(1);

	} catch (e) {
		handleCIException("getNextEntry", e)
	}
}

function putEntry() {
	logmsg("putEntry called");
	try {
		var writeMode = connector.getParam("writeMode") || "append";
		if (writeMode != "append") {
			throw new java.lang.Exception("Only 'append' writeMode is supported in putEntry");
		}

		var newRowNum = __sheet.getLastRowNum() + 1;
		var row       = __sheet.createRow(newRowNum);
		var keys      = __columnMap.keySet().toArray();

		for (var i = 0; i < keys.length; i++) {
			var colLetter = keys[i];
			var attrName  = __columnMap.get(colLetter);
			var colIndex  = getColumnIndex(colLetter);
			if (entry.getAttribute(attrName) != null) {
				row.createCell(colIndex).setCellValue(entry.getString(attrName));
			}
		}

		saveWorkbook();
		logmsg("Added new row at position: " + newRowNum);
		result.setStatus(1);

	} catch (e) {
		handleCIException("putEntry", e)
	}
}

function modEntry() {
	logmsg("modEntry called");
	try {
		if (__rowCache == null) buildRowCache();

		var fromLookup = connector.getFirstFindEntry();
		if (fromLookup) {
			for (var att in fromLookup) {
				if (!entry[att.getName()]) {
					entry.setAttribute(att)
				}
			}
			//entry["$uid"] = fromLookup["$uid"]
		}

		var keyValue;
		if (__uniqueKeyColumn != null) {
			keyValue = entry.getString(__columnMap.get(__uniqueKeyColumn));
		} else {
			keyValue = entry.getString("$uid") || entry.getString("$rowNumber");
		}

		if (keyValue == null) {
			throw new java.lang.Exception("Cannot modify entry: unique key value not found in conn");
		}

		var row = __rowCache.get(keyValue);
		if (row == null) {
			throw new java.lang.Exception("Row not found for key: " + keyValue);
		}

		var keys = __columnMap.keySet().toArray();
		for (var i = 0; i < keys.length; i++) {
			var colLetter = keys[i];
			var attrName  = __columnMap.get(colLetter);
			var colIndex  = getColumnIndex(colLetter);
			if (entry.getAttribute(attrName) != null) {
				var cell = row.getCell(colIndex) || row.createCell(colIndex);
				cell.setCellValue(entry.getString(attrName));
			}
		}

		saveWorkbook();
		logmsg("Modified row: " + row.getRowNum());
		result.setStatus(1);

	} catch (e) {
		handleCIException("modEntry", e)
	}
}

function deleteEntry() {
	logmsg("deleteEntry called");
	try {
		if (__rowCache == null) buildRowCache();

		var keyValue;
		if (__uniqueKeyColumn != null) {
			keyValue = entry.getString(__columnMap.get(__uniqueKeyColumn));
		} else {
			keyValue = entry.getString("$uid") || entry.getString("$rowNumber");
		}

		if (keyValue == null) {
			throw new java.lang.Exception("Cannot delete entry: unique key value not found in conn");
		}

		var row = __rowCache.get(keyValue);
		if (row == null) {
			throw new java.lang.Exception("Row not found for key: " + keyValue);
		}

		var rowNum = row.getRowNum();
		__sheet.removeRow(row);
		if (rowNum < __sheet.getLastRowNum()) {
			__sheet.shiftRows(rowNum + 1, __sheet.getLastRowNum(), -1);
		}

		saveWorkbook();
		logmsg("Deleted row: " + rowNum);

		__rowCache = null; // Force rebuild — row numbers have shifted
		result.setStatus(1);

	} catch (e) {
		handleCIException("deleteEntry", e)
	}
}

function findEntry() {
	logmsg("findEntry called");
	try {
		connector.clearFindEntries();

		if (__rowCache == null) buildRowCache();

		var searchResults   = new java.util.ArrayList();
		var searchType      = search.getType();
		var criteriaCount   = search.size();
		var fastPathHandled = false;

		// Fast-path: single EXACT match on unique key, $uid, or $rowNumber
		if (criteriaCount == 1) {
			var crit          = search.getCriteria(0);
			var uniqueKeyAttr = (__uniqueKeyColumn != null) ? __columnMap.get(__uniqueKeyColumn) : null;

			if (crit.match == search.EXACT &&
				(crit.name == uniqueKeyAttr || crit.name == "$uid" || crit.name == "$rowNumber")) {
				fastPathHandled = true;
				var row = __rowCache.get(crit.value);
				if (row != null) {
					searchResults.add(buildEntryFromRow(row));
				}
			}
		}

		// Full scan — only if fast-path key lookup was not applicable
		if (!fastPathHandled) {
			var iter = __sheet.iterator();
			if (__columnMapFromHeader || connector.getParam("skipHeader") == "true") {
				if (iter.hasNext()) iter.next();
			}

			while (iter.hasNext()) {
				var row        = iter.next();
				var candidate  = buildEntryFromRow(row);
				var matchCount = 0;

				for (var i = 0; i < criteriaCount; i++) {
					var crit = search.getCriteria(i);
					if (evaluateCriteria(candidate.getString(crit.name), crit.match, crit.value)) {
						matchCount++;
					}
				}

				var rowMatches;
				if (searchType == search.SEARCH_OR) {
					rowMatches = (matchCount > 0);
				} else if (searchType == search.SEARCH_NOT) {
					rowMatches = (matchCount == 0);
				} else { // SEARCH_AND (default)
					rowMatches = (matchCount == criteriaCount);
				}

				if (rowMatches) {
					searchResults.add(candidate);
				}
			}
		}

		if (searchResults.size() == 0) {
			result.setStatus(0);
			result.setMessage("No entries found");
		} else {
			result.setStatus(1);
			entry.removeAllAttributes();
			entry.merge(searchResults.get(0));
			for (var i = 0; i < searchResults.size(); i++) {
				connector.addFindEntry(searchResults.get(i));
			}
		}

	} catch (e) {
		handleCIException("findEntry", e)
	}
}

// Build an Entry from a POI Row using the current column map.
// Always sets every mapped attribute — blank cells write empty string
// to prevent value carry-over from the previous row via entry.merge().
function buildEntryFromRow(row) {
	var e    = system.newEntry();
	var keys = __columnMap.keySet().toArray();

	e.setAttribute("$rowNumber", row.getRowNum().toString());

	for (var i = 0; i < keys.length; i++) {
		var colLetter = keys[i];
		var attrName  = __columnMap.get(colLetter);
		var colIndex  = getColumnIndex(colLetter);
		var cellValue = getCellValue(row.getCell(colIndex));
		e.setAttribute(attrName, cellValue != null ? cellValue : "");
	}

	var dn = (__uniqueKeyColumn != null)
		? getCellValue(row.getCell(getColumnIndex(__uniqueKeyColumn)))
		: row.getRowNum().toString();
	e.setAttribute("$uid", dn);

	return e;
}

// Convert the value passed to a Float if possible
function numOrText(val, otherVal) {
	if (typeof(otherVal) == "string") {
		return String(val).trim()
	}

	try {
		var newVal = java.lang.Float(val);
		return newVal
	} catch(ex) {
		return val
	}
}

function evaluateCriteria(attrValue, matchType, searchValue) {
	if (attrValue == null) return false;

	var caseSensitive	= connector.getParam("caseSensitiveSearch");
	var a = numOrText(attrValue.toString());
	var s = numOrText((searchValue != null) ? searchValue.toString() : "", a);
	if (caseSensitive) {
		a = a.toUpperCase();
		s = s.toUpperCase()
	}


	if (matchType == search.EXACT)                 return a == s;
	if (matchType == search.NOT_STRING)            return a != s;
	if (matchType == search.SUBSTRING)             return a.indexOf(s) >= 0;
	if (matchType == search.INITIAL_STRING)        return a.indexOf(s) == 0;
	if (matchType == search.FINAL_STRING)          return a.length >= s.length && a.lastIndexOf(s) == a.length - s.length;

	if (matchType == search.LESS_THAN)             return a < s;
	if (matchType == search.LESS_THAN_OR_EQUAL)    return a <= s;
	if (matchType == search.GREATER_THAN)          return a > s;
	if (matchType == search.GREATER_THAN_OR_EQUAL) return a >= s;
/*
	if (matchType == search.LESS_THAN)             return parseFloat(a) < parseFloat(s);
	if (matchType == search.LESS_THAN_OR_EQUAL)    return parseFloat(a) <= parseFloat(s);
	if (matchType == search.GREATER_THAN)          return parseFloat(a) > parseFloat(s);
	if (matchType == search.GREATER_THAN_OR_EQUAL) return parseFloat(a) >= parseFloat(s);
*/
	logmsg("WARN", "evaluateCriteria: unhandled match type " + matchType);
	return false;
}

function querySchema() {
	logmsg("querySchema called");
	try {
		var keys = __columnMap.keySet().toArray();
		for (var i = 0; i < keys.length; i++) {
			var schemaEntry = system.newEntry();
			schemaEntry.addAttributeValue("name", __columnMap.get(keys[i]));
			schemaEntry.addAttributeValue("syntax", "String");
			list.add(schemaEntry);
		}

		var rowNumEntry = system.newEntry();
		rowNumEntry.addAttributeValue("name", "$rowNumber");
		rowNumEntry.addAttributeValue("syntax", "String");
		list.add(rowNumEntry);

		var dnEntry = system.newEntry();
		dnEntry.addAttributeValue("name", "$uid");
		dnEntry.addAttributeValue("syntax", "String");
		list.add(dnEntry);

		result.setStatus(1);

	} catch (e) {
		handleCIException("querySchema", e)
	}
}

function terminate() {
	logmsg("Terminating Excel XLSX Connector...");
	try {
		if (__workbook != null) {
			__workbook.close();
		}
	} catch (e) {
		logmsg("WARN", "Error closing workbook: " + e);
	} finally {
		__workbook            = null;
		__sheet               = null;
		__rowIterator         = null;
		__columnMap           = null;
		__columnMapFromHeader = false;
		__rowCache            = null;
		__evaluator           = null;
		__dataFormatter       = null;
		logmsg("Excel XLSX Connector terminated");
	}
}

Script.parameter:
// The args properties are optional and include:
//
//		filenameTemplate: optional name (with subst-tokens) of the Excel sheet, in case it is written to disk
//    	sheetFileName: filepath for the Excel Sheet used by write() method, default is "$TDI_SOLDIR/_ExcelSheet.xlsx
//						NOTE: may contain eval tokens in curly braces - support javascript
//		columnsFileName: filepath to the text file with ordered names of Sheet columns, one per line
//	 OR columnNames: semicolon-separated list of field names (instead of file)
//		entry: Entry that the sheetFileName evaluation should use for eval tokens - i.e. {attribute-name}
//
var ExcelObj = function (args)
{
	//this.vrs = "20200602 1725"; // First version
	//this.vrs = "20200603 1345"; // Finally working
	//this.vrs = "20200603 2232"; // Corrected filename generation
	//this.vrs = "20200703 2000"; // .generate() can return ByteArray
	//this.vrs = "20200705 1408" // Removed POC_MVP/ as default path for files
	//this.vrs = "20200711 1839" // Added support for multiple entries with .addRow() and .writeSheet()
	//this.vrs = "20200712 1658"; // Added .getBytes() method
	//this.vrs = "20200810 1905"; // Removed debug code for sheetname
	//this.vrs = "20200815 1556"; // Removed hardcoded sheetname
	//this.vrs = "20200815 1556"; // Removed hardcoded sheetname
	//this.vrs = "2020921 1057"; // Added columnNames constructor argument
	//this.vrs = "20200925 1010"; // Changed name to ExcelObj and .writeSheet() to .write()
	this.vrs = "20201030 1557"; // Added feature to addRow so that Att Names starting with pipe (|) will be in bold font

	args = args || {};

	this.filenameTemplate = typeof(args) == "string" ? args : (args.fileName || "_ExcelWorkbook.xlsx");
	this.filename = "_ExcelWorkbook.xlsx";
	this.sheetname = args.sheetname || "Data";
	this.entry = args.entry || system.newEntry();
	this.map = new Mapper();
	this.columns = null;
	this.columnsFileName = args.columnsFileName || null;
	this.columnNames = args.columnNames || null;

	this.workbook = null;
	this.spreadsheet = {};
	this.rowCount = {} ;

	// Used for copying spreadsheets
	this.workbooks = {};
	this.sheets = {};
	this.rowIndex = {};

	// Local log function
	this.log = function(lvl, msg, throwit) {
		throwit = throwit || false;

		if (typeof lvl == "undefined") {
			msg = "";
			lvl = "INFO";
		} else
		if (typeof msg == "undefined") {
			msg = lvl;
			lvl = "INFO";
		}

		log(lvl, "[ExcelObj] " + msg);

		if (throwit) throw "[ExcelObj] " + msg;
	}

	// Write the workbook to a file
	this.write = function(useFileName) {
		useFileName = useFileName || this.filename;
		var fos = new java.io.FileOutputStream(new java.io.File(useFileName));
		this.workbook.write(fos);
		fos.close();
	}

	// Return the workbook as a byte array
	this.getBytes = function() {
		var fos = new java.io.ByteArrayOutputStream();
		this.workbook.write(fos);
		fos.close();

		return fos.toByteArray();
	}

	// Add an Entry as a row to this spreadsheet, using the field list specified
	this.addRow = function(entry, toSheetName, columns) {
		columns = columns || this.columns;
		toSheetName = toSheetName || this.sheetname;

		var row;
		if (this.workbook == null) {
			//Blank Document
			this.workbook = new org.apache.poi.xssf.usermodel.XSSFWorkbook();

			var boldFont = this.workbook.createFont();
	        boldFont.setBold(true);

	        this.headerStyle = this.workbook.createCellStyle();
	        this.headerStyle.setBorderBottom(org.apache.poi.ss.usermodel.BorderStyle.MEDIUM);
	        this.headerStyle.setBorderTop(org.apache.poi.ss.usermodel.BorderStyle.MEDIUM);
	        this.headerStyle.setBorderRight(org.apache.poi.ss.usermodel.BorderStyle.MEDIUM);
	        this.headerStyle.setBorderLeft(org.apache.poi.ss.usermodel.BorderStyle.MEDIUM);
	        this.headerStyle.setFillForegroundColor(200);
	        this.headerStyle.setFillPattern(org.apache.poi.ss.usermodel.FillPatternType.SOLID_FOREGROUND);
	        //headerStyle.setVerticalAlignment(org.apache.poi.ss.usermodel.VerticalAlignment.TOP);
	        this.headerStyle.setAlignment(org.apache.poi.ss.usermodel.HorizontalAlignment.CENTER);
	        this.headerStyle.setFont(boldFont);			

			this.cellStyle = this.workbook.createCellStyle();
			this.cellStyle.setWrapText(true);
	        this.cellStyle.setAlignment(org.apache.poi.ss.usermodel.HorizontalAlignment.LEFT);

			this.boldCellStyle = this.workbook.createCellStyle();
			this.boldCellStyle.setWrapText(true);
	        this.boldCellStyle.setAlignment(org.apache.poi.ss.usermodel.HorizontalAlignment.LEFT);
	        this.boldCellStyle.setFillForegroundColor(200);
	        this.boldCellStyle.setFillPattern(org.apache.poi.ss.usermodel.FillPatternType.SOLID_FOREGROUND);
	        this.boldCellStyle.setFont(boldFont);			
		}

		if (!this.spreadsheet[toSheetName]) {
			this.spreadsheet[toSheetName] = this.workbook.createSheet(toSheetName);
			this.rowCount[toSheetName] = 0;
		}

		if (this.rowCount[toSheetName] == 0) {
			row = this.spreadsheet[toSheetName].createRow(this.rowCount[toSheetName]);
			for (var cellNum = 0; cellNum < columns.length; cellNum++) {
				var name = columns[cellNum];
				var xlCell = row.createCell(cellNum);
				xlCell.setCellStyle(this.headerStyle);
				xlCell.setCellValue(name);
		        this.spreadsheet[toSheetName].autoSizeColumn(cellNum);
			}
			this.rowCount[toSheetName]++;
		}

		row = this.spreadsheet[toSheetName].createRow(this.rowCount[toSheetName]);
		for (var cellNum = 0; cellNum < columns.length; cellNum++) {
			var name = columns[cellNum];
			var bold = false;

			// First look if the attribute name is prepended with pipe (|) and if so, it's to be BOLDed
			var att = entry["|" + name];
			if (att == null) {
				att = entry[name];	
			}

			var value = null;
			if (att != null) {
				var attName = att.getName();

				// Pipe symbol prefix indicates Bold font
				if (attName.startsWith("|")) {
					bold = true;
				}
				var values = att.getValues();
				if (values.length == 1) {
					var value = values[0];
				} else {
					//row.setHeightInPoints((Math.max(1, values.length) * this.spreadsheet[toSheetName].getDefaultRowHeightInPoints()));
					var arr = [];
					for (var value in values) {
						arr.push(value.trim());
					}
					var value = arr.join("\n");
				}
			}	

			var xlCell = row.createCell(cellNum);
			if (bold) {
	 			xlCell.setCellStyle(this.boldCellStyle);
			} else {
	 			xlCell.setCellStyle(this.cellStyle);
			}
			xlCell.setCellValue(value);
		}

		this.rowCount[toSheetName]++;
	}

	// Initialize this object
	this.initialize = function() {
		this.log(" v" + this.vrs);

		if (this.columnsFileName) {
			var file = new java.io.File(this.columnsFileName) 
			if (!file.exists()) {
				this.log("FATAL", "Columns file name does not exist: " + this.columnsFileName, true);
			}

			this.columns = loadFileToArray(this.columnsFileName);
		} else 
		if (this.columnNames) {
			var sep = ",";
			if (this.columnNames.contains(";")) {
				sep = ";";
			}
			this.columns = system.splitString(this.columnNames, sep);
		}

		if (String(this.filenameTemplate).trim() != "") {
			this.filename = this.map.evaluate("Excel sheet filename", this.filenameTemplate, this.entry);
		}
	}	

	// Initialization code below here

	this.initialize();

	return this;
}

var WordDoc = function (filenameTemplate)
{
	//this.vrs = "20200602 1725"; // First version
	//this.vrs = "20200603 1345"; // Updated to handle templating
	this.vrs = "20200603 2232"; // Corrected filename generation

	this.filenameTemplate = filenameTemplate;
	this.map = new Mapper();

	this.log = function(lvl, msg) {
		if (typeof lvl == "undefined") {
			msg = "";
			lvl = "INFO";
		} else
		if (typeof msg == "undefined") {
			msg = lvl;
			lvl = "INFO";
		}

		log(lvl, "[WordDoc] " + msg);
	}

	// 

	// Generate a Word Doc based on a file template
	this.generate = function(entry) {
		// Get filename
		filename = this.map.evaluate("Word doc filename", this.filenameTemplate, entry);
		this.log("Generating Word doc: " + filename);

		//Blank Document
		var document = new org.apache.poi.xwpf.usermodel.XWPFDocument();

		//Write the Document in file system
		//fos = new java.io.ByteArrayOutputStream();
		fos = new java.io.FileOutputStream(new java.io.File("POC_MVP/" + filename));

		// First create the Abstract
		var paragraph = document.createParagraph();
		var run = paragraph.createRun();
		run.setBold(true);
		run.setFontSize(12);

		var contents = entry.getString("contents");
		var lines = system.splitString(contents, "\n");

		for (var line in lines) {
			run.setText(line);
			run.addBreak();
		}

		document.write(fos);
		fos.close();

		if (fos instanceof java.io.ByteArrayOutputStream) {
			return fos.toByteArray();
		}
	}

	this.initialize = function() {
		this.log(" v" + this.vrs);
	}	

	// Initialization code below here

	this.initialize();

	return this;
}

